// ========================================
// ANALYZE CONTEXT & SELECT MESSAGE
// Thư viện tin nhắn đa dạng, ít lặp
// ========================================

const tasks = $input.first().json.results || [];
const today = new Date();
const dayOfWeek = today.getDay(); // 0=Sun, 1=Mon, 5=Fri
const dayOfMonth = today.getDate();

// ========== THƯ VIỆN TIN NHẮN ==========
const MESSAGE_LIBRARY = {

  // STREAK CELEBRATION
  streak_3_days: [
    "3 ngày liên tục rồi đó anh! Momentum đang tốt lắm ạ 🔥",
    "Wow, 3 ngày không nghỉ! Anh đang trên đà chiến thắng rồi ạ",
    "Đỉnh quá anh ơi! 3 ngày streak - cứ đà này là xuất sắc",
    "3 ngày kiên trì! Em thấy anh đang vào guồng rồi đó ạ",
    "Hat-trick rồi anh! 3 ngày liên tục cập nhật, tuyệt vời ạ"
  ],

  streak_7_days: [
    "1 tuần liên tục! Anh là nguồn cảm hứng của em đó ạ ⭐",
    "7 ngày không đứt mạch! Anh thuộc top 1% người kiên trì rồi",
    "Cả tuần đều đặn! Em phục anh quá, consistency is key mà",
    "1 week streak! Nếu có huy hiệu thì anh xứng đáng nhận rồi ạ",
    "7 ngày rồi đó anh! Thói quen tốt đang hình thành rồi ạ"
  ],

  // GENTLE NUDGE (2-3 ngày)
  nudge_2_days: [
    "Anh ơi, 2 ngày rồi em chưa thấy anh ghé qua. Mọi thứ ổn chứ ạ?",
    "Hôm nay anh có muốn cập nhật gì không ạ? Em đợi sẵn rồi",
    "2 ngày rồi đó anh, có task nào cần em hỗ trợ không ạ?",
    "Anh đang bận việc khác hả? Khi nào rảnh ghé qua nhé ạ",
    "Em thấy vài task sắp đến hạn, anh xem qua khi có thời gian nhé"
  ],

  nudge_3_days: [
    "3 ngày rồi anh ơi! Em hơi lo, có gì khó khăn không ạ?",
    "Anh ơi, mấy task đang chờ anh cập nhật nè. Rảnh ghé qua nhé",
    "Em để ý 3 ngày chưa thấy anh. Công việc nhiều quá hả anh?",
    "Hú anh! 3 ngày rồi đó, có cần em nhắc việc gì không ạ?",
    "Anh đâu rồi? 3 ngày em ngóng anh ghé qua mà chưa thấy"
  ],

  // RE-ENGAGEMENT (5-7 ngày)
  reengagement_5_days: [
    "5 ngày rồi anh ơi... Em nhớ anh quá! Khi nào rảnh ghé qua nhé",
    "Anh ơi, gần tuần rồi chưa thấy anh. Em vẫn đợi anh ở đây ạ",
    "5 ngày không gặp! Anh có khỏe không? Em lo lắng quá",
    "Hú hú anh ơi! Streak đang chờ anh quay lại nè",
    "5 ngày rồi đó, nhưng không sao, em vẫn ở đây chờ anh ạ"
  ],

  reengagement_7_days: [
    "Cả tuần rồi anh ơi 🥺 Em nhớ những ngày anh ghé qua lắm",
    "7 ngày không thấy anh, em lo quá. Anh ổn chứ ạ?",
    "1 tuần rồi... Em không muốn làm phiền, nhưng em lo anh",
    "Anh ơi, tuần này bận lắm hả? Khi nào rảnh nhớ ghé qua nhé",
    "7 ngày em ngóng anh! Streak cũ đã mất nhưng streak mới chờ anh"
  ],

  // DEADLINE ALERTS
  deadline_tomorrow: [
    "Anh ơi, có task đến hạn ngày mai nè. Anh xem qua nhé ạ",
    "Nhắc anh nhẹ: ngày mai có deadline rồi đó ạ",
    "Hú anh! Mai là hạn chót nè, anh check qua nhé",
    "Anh ơi, 24h nữa là deadline. Cần em hỗ trợ gì không ạ?",
    "Countdown: 1 ngày nữa là đến hạn. Anh check qua nhé"
  ],

  deadline_today: [
    "Hôm nay là D-day rồi anh ơi! Tình hình thế nào ạ?",
    "Anh ơi, deadline là HÔM NAY. Anh cập nhật giúp em nhé",
    "🚨 Task đến hạn hôm nay ạ. Tình hình thế nào rồi?",
    "D-day đây rồi anh! Có cần em support gì không ạ?",
    "Hôm nay là ngày quyết định! Fighting anh! 💪"
  ],

  deadline_overdue: [
    "Anh ơi, có task đã quá hạn rồi ạ. Có khó khăn gì không?",
    "Em thấy task này quá deadline rồi. Anh cần thêm thời gian không ạ?",
    "Task đã overdue, nhưng không sao, em ở đây hỗ trợ anh",
    "Quá hạn rồi anh ơi. Mình cập nhật lại timeline nhé?",
    "Task này cần attention nè anh. Em giúp gì được không ạ?"
  ],

  // MONDAY MOTIVATION
  monday_start: [
    "Thứ Hai rồi anh ơi! Tuần mới, năng lượng mới. Fighting! 💪",
    "Đầu tuần rồi! Mình bắt đầu tuần mới thật hiệu quả nhé?",
    "Happy Monday anh! Tuần này mình chiến thắng nhé",
    "Thứ 2 đây rồi! Em đã chuẩn bị sẵn list tasks cho anh",
    "New week, new wins! Anh sẵn sàng chưa ạ?"
  ],

  // FRIDAY WRAP-UP
  friday_wrapup: [
    "Thứ 6 rồi anh! Tuần này vất vả quá, nghỉ ngơi nhé ạ",
    "TGIF anh ơi! Cuối tuần vui vẻ nhé",
    "Hết tuần rồi! Anh đã cố gắng nhiều lắm, weekend thư giãn nhé",
    "Friday đây! Tuần sau mình tiếp tục, giờ thì enjoy weekend ạ",
    "Cuối tuần rồi anh! Cảm ơn anh đã kiên trì cả tuần qua 🙏"
  ],

  // NEW MONTH
  new_month: [
    "Tháng mới rồi anh! Fresh start, fresh goals. Let's go! 🚀",
    "Chào tháng mới! Tháng trước anh làm tốt lắm, tháng này còn tốt hơn nhé",
    "Ngày đầu tháng! Reset và chinh phục mục tiêu mới nào anh"
  ],

  // NORMAL DAY (có task nhưng không urgent)
  normal_day: [
    "Chào anh! Hôm nay anh có task nào cần xử lý không ạ?",
    "Ngày mới tốt lành anh! Em ở đây sẵn sàng hỗ trợ anh",
    "Hi anh! Có gì cần em nhắc không ạ?",
    "Anh ơi, hôm nay mình productive nhé!",
    "Chúc anh một ngày làm việc hiệu quả ạ!"
  ]
};

// ========== ANALYZE TASKS ==========
let overdueCount = 0;
let todayDeadlineCount = 0;
let tomorrowDeadlineCount = 0;
let urgentTasks = [];

for (var i = 0; i < tasks.length; i++) {
  var task = tasks[i];
  var props = task.properties || {};

  // Lấy deadline
  var deadlineField = null;
  for (var key in props) {
    if (key.toLowerCase().indexOf('thời hạn') !== -1 || key.toLowerCase().indexOf('t4') !== -1) {
      deadlineField = props[key];
      break;
    }
  }

  if (deadlineField && deadlineField.date && deadlineField.date.start) {
    var deadline = new Date(deadlineField.date.start);
    var diffDays = Math.ceil((deadline - today) / (1000 * 60 * 60 * 24));

    // Lấy title
    var title = '';
    for (var key2 in props) {
      if (props[key2].type === 'title' && props[key2].title && props[key2].title[0]) {
        title = props[key2].title[0].plain_text || '';
        break;
      }
    }

    if (diffDays < 0) {
      overdueCount++;
      urgentTasks.push({ title: title, status: 'overdue', days: diffDays });
    } else if (diffDays === 0) {
      todayDeadlineCount++;
      urgentTasks.push({ title: title, status: 'today', days: 0 });
    } else if (diffDays === 1) {
      tomorrowDeadlineCount++;
      urgentTasks.push({ title: title, status: 'tomorrow', days: 1 });
    }
  }
}

// ========== SELECT MESSAGE CATEGORY ==========
var category = 'normal_day';
var priority = 0;

// Ưu tiên 1: Overdue (cao nhất)
if (overdueCount > 0) {
  category = 'deadline_overdue';
  priority = 100;
}
// Ưu tiên 2: Today deadline
else if (todayDeadlineCount > 0) {
  category = 'deadline_today';
  priority = 90;
}
// Ưu tiên 3: Tomorrow deadline
else if (tomorrowDeadlineCount > 0) {
  category = 'deadline_tomorrow';
  priority = 80;
}
// Ưu tiên 4: Special days
else if (dayOfMonth === 1) {
  category = 'new_month';
  priority = 50;
}
else if (dayOfWeek === 1) { // Monday
  category = 'monday_start';
  priority = 40;
}
else if (dayOfWeek === 5) { // Friday
  category = 'friday_wrapup';
  priority = 40;
}

// ========== GET RANDOM MESSAGE ==========
var messages = MESSAGE_LIBRARY[category] || MESSAGE_LIBRARY['normal_day'];
var randomIndex = Math.floor(Math.random() * messages.length);
var selectedMessage = messages[randomIndex];

// ========== BUILD TASK SUMMARY ==========
var taskSummary = '';
if (urgentTasks.length > 0) {
  taskSummary = '\n\n📋 Tasks cần chú ý:\n';
  for (var j = 0; j < Math.min(urgentTasks.length, 5); j++) {
    var t = urgentTasks[j];
    if (t.status === 'overdue') {
      taskSummary += '• 🔴 ' + t.title + ' (quá hạn ' + Math.abs(t.days) + ' ngày)\n';
    } else if (t.status === 'today') {
      taskSummary += '• 🟠 ' + t.title + ' (hôm nay)\n';
    } else {
      taskSummary += '• 🟡 ' + t.title + ' (ngày mai)\n';
    }
  }
}

// ========== BUILD STATS ==========
var stats = {
  totalActive: tasks.length,
  overdue: overdueCount,
  dueToday: todayDeadlineCount,
  dueTomorrow: tomorrowDeadlineCount
};

// ========== DECIDE IF SHOULD SEND ==========
// Không gửi nếu:
// - Cuối tuần (Sat/Sun) và không có urgent
// - Không có task nào
var shouldSend = true;
if ((dayOfWeek === 0 || dayOfWeek === 6) && priority < 80) {
  shouldSend = false; // Weekend, không urgent
}
if (tasks.length === 0) {
  shouldSend = false; // Không có task
}

return {
  shouldSend: shouldSend,
  category: category,
  message: selectedMessage,
  taskSummary: taskSummary,
  stats: stats,
  urgentTasks: urgentTasks,
  dayOfWeek: dayOfWeek,
  dayOfMonth: dayOfMonth,
  priority: priority
};
